    assertEquals(422, response.statusCode(), "status code mismatch")
    val bodyJson = MAPPER.readTree(response.body())
    val expectedJson = MAPPER.readTree("{\"detail\":\"1 validation error in request\",\"errors\":[{\"ctx\":{\"min_length\":3},\"input\":\"ab\",\"loc\":[\"body\",\"username\"],\"msg\":\"String should have at least 3 characters\",\"type\":\"string_too_short\"}],\"status\":422,\"title\":\"Request Validation Failed\",\"type\":\"https://spikard.dev/errors/validation-error\"}")
    assertEquals(expectedJson, bodyJson, "body mismatch")
}

}
